// The previous attempt asserted post1_netc.my_end_point() == pre_netc.my_end_point()
// (and friends) as bare facts.  That failed because the ensures of
// receive_with_demarshal are NOT hypotheses of det_receive_with_demarshal — they
// sit inside the antecedent of det_<f>'s implication ensures.  To use them we
// need to enter that antecedent via `assert(A ==> B) by { ... }`, which
// hypothecates A while we discharge B.
//
// We also concretize the let-bindings `let (rr, net_event) = r1/r2` by binding
// rr1/ne1 and rr2/ne2 in the proof body so the two ensures conjuncts have
// matching anchor terms (`r1.0`, `r1.1@`, `r2.0`, `r2.1@`) — closing the
// trigger gap that left z3 returning `unknown`.

let (rr1, ne1) = r1;
let (rr2, ne2) = r2;

assert(({
    &&& ({
        &&& post1_netc.my_end_point() == pre_netc.my_end_point()
        &&& post1_netc.ok() == !(rr1 is Fail)
        &&& (!(rr1 is Fail) ==> post1_netc.ok() && post1_netc.history() == pre_netc.history() + seq!(ne1@))
        &&& (rr1 is Timeout ==> ne1@ is TimeoutReceive)
        &&& (rr1 is Packet ==> {
            &&& ne1@ is Receive
            &&& rr1.arrow_Packet_cpacket().abstractable()
            &&& (!(rr1.arrow_Packet_cpacket()@.msg is InvalidMessage) ==> {
                &&& rr1.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(ne1@.arrow_Receive_r())
                &&& rr1.arrow_Packet_cpacket().msg@ == sht_demarshal_data(ne1@.arrow_Receive_r().msg)@
            })
            &&& rr1.arrow_Packet_cpacket().dst@ == local_addr@
        })
    })
    &&& ({
        &&& post2_netc.my_end_point() == pre_netc.my_end_point()
        &&& post2_netc.ok() == !(rr2 is Fail)
        &&& (!(rr2 is Fail) ==> post2_netc.ok() && post2_netc.history() == pre_netc.history() + seq!(ne2@))
        &&& (rr2 is Timeout ==> ne2@ is TimeoutReceive)
        &&& (rr2 is Packet ==> {
            &&& ne2@ is Receive
            &&& rr2.arrow_Packet_cpacket().abstractable()
            &&& (!(rr2.arrow_Packet_cpacket()@.msg is InvalidMessage) ==> {
                &&& rr2.arrow_Packet_cpacket()@ == abstractify_net_packet_to_sht_packet(ne2@.arrow_Receive_r())
                &&& rr2.arrow_Packet_cpacket().msg@ == sht_demarshal_data(ne2@.arrow_Receive_r().msg)@
            })
            &&& rr2.arrow_Packet_cpacket().dst@ == local_addr@
        })
    })
}) ==> det_receive_with_demarshal_equal(r1, r2, post1_netc, post2_netc)) by {
    // Inside the by-block the entire antecedent is a hypothesis.  Surface each
    // per-run conjunct as a separately named fact in terms of the concretized
    // rr1/ne1 / rr2/ne2 names so the two ensures clauses line up.
    assert(post1_netc.my_end_point() == pre_netc.my_end_point());
    assert(post2_netc.my_end_point() == pre_netc.my_end_point());
    assert(post1_netc.ok() == !(rr1 is Fail));
    assert(post2_netc.ok() == !(rr2 is Fail));

    // Cross-run consequence: my_end_points agree, both runs route through pre_netc.
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());

    // History extension (only meaningful on non-Fail).
    if !(rr1 is Fail) {
        assert(post1_netc.ok());
        assert(post1_netc.history() == pre_netc.history() + seq!(ne1@));
    }
    if !(rr2 is Fail) {
        assert(post2_netc.ok());
        assert(post2_netc.history() == pre_netc.history() + seq!(ne2@));
    }

    // Case-by-variant facts for r1.
    if rr1 is Timeout {
        assert(ne1@ is TimeoutReceive);
    }
    if rr1 is Packet {
        assert(ne1@ is Receive);
        assert(rr1.arrow_Packet_cpacket().abstractable());
        assert(rr1.arrow_Packet_cpacket().dst@ == local_addr@);
    }

    // Case-by-variant facts for r2.
    if rr2 is Timeout {
        assert(ne2@ is TimeoutReceive);
    }
    if rr2 is Packet {
        assert(ne2@ is Receive);
        assert(rr2.arrow_Packet_cpacket().abstractable());
        assert(rr2.arrow_Packet_cpacket().dst@ == local_addr@);
    }
};
